import { describe, test, expect } from 'bun:test';
import { GnosisRegistry } from '../runtime/registry.js';
import type { GnosisHandler } from '../runtime/registry.js';

describe('GnosisRegistry', () => {
    test('registers and retrieves a handler', async () => {
        const registry = new GnosisRegistry();
        const handler: GnosisHandler = async (payload) => payload * 2;
        registry.register('Double', handler);

        const retrieved = registry.getHandler('Double');
        expect(retrieved).toBeDefined();
        expect(await retrieved!('5', {})).toBe(10);
    });

    test('returns undefined for unregistered handler', () => {
        const registry = new GnosisRegistry();
        expect(registry.getHandler('NonExistent')).toBeUndefined();
    });

    test('overwrites handler on duplicate registration', async () => {
        const registry = new GnosisRegistry();
        registry.register('Op', async () => 'first');
        registry.register('Op', async () => 'second');

        const result = await registry.getHandler('Op')!(null, {});
        expect(result).toBe('second');
    });

    test('handlers receive payload and properties', async () => {
        const registry = new GnosisRegistry();
        registry.register('Echo', async (payload, props) => {
            return { payload, props };
        });

        const handler = registry.getHandler('Echo')!;
        const result = await handler([1, 2, 3], { mode: 'test' });
        expect(result.payload).toEqual([1, 2, 3]);
        expect(result.props.mode).toBe('test');
    });

    test('supports multiple independent handlers', () => {
        const registry = new GnosisRegistry();
        registry.register('A', async () => 'a');
        registry.register('B', async () => 'b');
        registry.register('C', async () => 'c');

        expect(registry.getHandler('A')).toBeDefined();
        expect(registry.getHandler('B')).toBeDefined();
        expect(registry.getHandler('C')).toBeDefined();
    });
});
